INSERT INTO `notification_logs` VALUES (1,3,'email','sahodayapune24@gmail.com','School login password reset - Sahodaya Schools Complex','Dear School Admin,\n\nThe login password for Trinity International School, has been reset by Sahodaya admin.\n\nLogin URL: http://localhost/sahodaya/auth/login.php\nLogin Email: sahodayapune24@gmail.com\nNew Password: pune@123\n\nPlease login and keep this password secure.\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-22 08:42:41'),(2,3,'email','sahodayapune24@gmail.com','School profile change rejected - Sahodaya Schools Complex','Dear Dr. Rupali Dhamdhere,\n\nYour school profile change request for Trinity International School, has been rejected.\nPlease login and submit corrected details if required.\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-22 08:45:23'),(3,3,'email','sahodayapune24@gmail.com','School profile change approved - Sahodaya Schools Complex','Dear Dr. Rupali Dhamdheree,\n\nYour school profile change request for Trinity International School, has been approved.\nThe approved information is now visible on the public member schools page.\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-22 08:49:03'),(4,NULL,'email','test@gmail.com','Membership approved - Sahodaya Schools Complex','Dear test msg,\n\nYour Sahodaya membership for Trinity International School pune has been approved.\n\nYou can now login and request profile edits when school details change.\nLogin URL: http://localhost/sahodaya/auth/login.php\nLogin Email: test@gmail.com\nPassword: Use the password submitted during membership registration.\n\nProfile edit rule: submitted changes are sent to admin first and publish only after approval.\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-22 12:30:45'),(5,NULL,'email','gaikwadkoamlgaikwad2000@gmail.com','Membership approved - Sahodaya Schools Complex','Dear Dr. Rupali Dhamdhere,\n\nYour Sahodaya membership for Trinity International School, has been approved.\n\nYou can now login and request profile edits when school details change.\nLogin URL: http://localhost/sahodaya/auth/login.php\nLogin Email: gaikwadkoamlgaikwad2000@gmail.com\nPassword: Use the password submitted during membership registration.\n\nProfile edit rule: submitted changes are sent to admin first and publish only after approval.\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-25 11:35:23'),(10,NULL,'email','dummy-renewal-test@sahodaya.local','Membership renewal reminder - RENEWAL TEST SCHOOL - 10 days - 2026-06-07','Dear Dummy Principal,\n\nYour Sahodaya membership will expire in 10 days.\nSchool: RENEWAL TEST SCHOOL\nExpiry Date: 07 Jun 2026\n\nPlease contact the Sahodaya team and complete annual membership renewal payment.\nLogin URL: http://localhost./auth/login.php\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-28 08:02:14'),(11,NULL,'email','info@sahodaya.org','Admin alert: membership renewal due - RENEWAL TEST SCHOOL - 10 days - 2026-06-07','Dear Admin Team,\n\nThis school membership will expire in 10 days.\n\nSchool: RENEWAL TEST SCHOOL\nPrincipal: Dummy Principal\nRegistered Email: dummy-renewal-test@sahodaya.local\nPhone: +91 90000 99999\nExpiry Date: 07 Jun 2026\n\nPlease connect with the school for annual membership renewal.\n\nRegards,\nSahodaya Schools Complex','pending',NULL,'2026-05-28 08:02:17');
